VALUES
('std_pri_001', 'PRIVAXIS', 'STATE_STATUTE', 'CA', 'Cal. Civ. Code §§ 1798.100-1798.199.100', 'CCPA/CPRA', 'California Consumer Privacy Act (as amended by CPRA)', 'Comprehensive consumer privacy law granting rights to know, delete, correct, opt-out, and limit use of personal information.', '["Right to know what personal information is collected","Right to delete personal information","Right to opt-out of sale/sharing","Right to correct inaccurate personal information","Right to limit use of sensitive personal information","12-month lookback period"]', '[{"section":"1798.100","description":"Right to know and access"},{"section":"1798.105","description":"Right to delete"},{"section":"1798.106","description":"Right to correct"},{"section":"1798.120","description":"Right to opt-out of sale/sharing"},{"section":"1798.121","description":"Right to limit sensitive PI use"},{"section":"1798.150","description":"Private right of action for data breaches"}]', '["privacy_policy","data_request","opt_out_request","data_breach_notice"]', '[]', 'California Privacy Protection Agency (CPPA)', 1, 1, datetime('now'), datetime('now'));

INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_pri_002', 'PRIVAXIS', 'STATE_STATUTE', 'CA', 'Cal. Civ. Code §§ 1798.29, 1798.82', 'CA Data Breach', 'California Data Breach Notification Law', 'Requires businesses to notify California residents when their personal information is exposed in a data breach.', '["Notify affected individuals in most expedient time possible","Notification must include specific content elements","Notify AG if breach affects 500+ residents","Encryption is a safe harbor"]', '[{"section":"1798.29","description":"Agency breach notification requirements"},{"section":"1798.82","description":"Business breach notification requirements"}]', '["breach_notice","incident_report","AG_notification"]', '[]', 'California AG', 1, 1, datetime('now'), datetime('now'));

