VALUES
('std_pri_003', 'PRIVAXIS', 'FEDERAL_STATUTE', 'US', '45 CFR Parts 160, 164 (HIPAA)', 'HIPAA', 'Health Insurance Portability and Accountability Act — Privacy & Security Rules', 'Federal standards for protecting individually identifiable health information (PHI).', '["Privacy Rule: limits use and disclosure of PHI","Security Rule: administrative, physical, technical safeguards","Breach Notification Rule: notify within 60 days","Minimum necessary standard for disclosures"]', '[{"section":"164.502","description":"Uses and disclosures of PHI"},{"section":"164.508","description":"Authorization requirements"},{"section":"164.312","description":"Technical safeguards"},{"section":"164.410-414","description":"Breach notification requirements"}]', '["medical_record","authorization_form","breach_notice","BAA"]', '[]', 'HHS Office for Civil Rights', 1, 1, datetime('now'), datetime('now'));


