('std_int_002', 'INTEGRA', 'COURT_RULE', 'CA', 'California Rules of Court, Rule 5.250', 'CRC 5.250', 'Mandatory Custody Evaluation Procedures', 'Procedures for court-ordered custody evaluations including qualifications, methodology, and report requirements.', '["Evaluator must meet minimum qualifications","Both parties must have opportunity to participate","Report must address best interest factors","Must be completed within court timeframe"]', '[{"section":"5.250(a)","description":"Appointment of evaluator"},{"section":"5.250(b)","description":"Minimum qualifications"},{"section":"5.250(c)","description":"Evaluation methodology"}]', '["custody_evaluation","730_report","court_order"]', '["automated-structuring-input-refiner","project-context-and-guardrails"]', 'Superior Court of California', 0, 1, datetime('now'), datetime('now'));

