('std_int_003', 'INTEGRA', 'STATE_STATUTE', 'CA', 'Cal. Bus. & Prof. Code § 6125', 'B&P § 6125', 'Unauthorized Practice of Law', 'Only active members of the State Bar may practice law in California. AI-assisted compliance tools must not cross this boundary.', '["Only licensed attorneys may practice law","Providing legal advice constitutes practice of law","Legal information vs. legal advice distinction","Compliance platforms must disclaim legal advice"]', '[{"section":"6125","description":"Prohibition on unauthorized practice"},{"section":"6126","description":"Penalties for unauthorized practice"}]', '["platform_disclaimer","compliance_report","legal_information"]', '["master-project-intake-audit-triage","project-context-and-guardrails"]', 'State Bar of California', 1, 1, datetime('now'), datetime('now'));
